sql:
SELECT dg.generator_name, dg.max_data_size
FROM testing_results AS tr
INNER JOIN data_generators AS dg ON tr.datagenerator = dg.generator_id;

external_knowledge:
- 'Free' license type refers to database management systems that are open-source or do not require a purchase to use; 
- A score numerator greater than 500 indicates a high performance or efficiency level of the DBMS, although the exact scoring system is not provided;
- The time taken (timetaken) being greater than 100 seconds implies that the DBMS has been used for processes that require a significant amount of time, possibly indicating complex operations or large data sets.

sql:
SELECT DISTINCT dbms_name, version
FROM dbms_details
ORDER BY last_updated DESC;

SELECT result_id, tests, timetaken
FROM testing_results
ORDER BY tests DESC;

SELECT result_id, timetaken 
FROM testing_results 
ORDER BY timetaken DESC;

SELECT generator_name, description, data_type_supported, max_data_size, last_used
FROM data_generators
WHERE generator_id IN (
    SELECT datagenerator
    FROM testing_results
);

SELECT session_type, AVG(JULIANDAY(end_time) - JULIANDAY(start_time)) AS average_duration
FROM testing_sessions
GROUP BY session_type;

SELECT technique, AVG(scorenumerator) AS Average_Scorenumerator
FROM testing_results
GROUP BY technique;
